"""localize — stub i18n helper for setup strings (ARCH-94, multilingual requirement)."""

from __future__ import annotations

# Map of (key, lang) -> translated string.
# Production would load from locale files; this stub returns the key for any lang
# not explicitly listed here.
_STRINGS: dict[tuple[str, str], str] = {
    # EU AI Act disclosure
    ("ai_act_disclosure", "en"): (
        "This response is generated by an AI assistant (StackOwl). "
        "AI can make mistakes. Verify important information independently."
    ),
    ("ai_act_disclosure", "de"): (
        "Diese Antwort wurde von einem KI-Assistenten (StackOwl) generiert. "
        "KI kann Fehler machen. Überprüfen Sie wichtige Informationen unabhängig."
    ),
    ("ai_act_disclosure", "fr"): (
        "Cette réponse est générée par un assistant IA (StackOwl). "
        "L'IA peut faire des erreurs. Vérifiez les informations importantes indépendamment."
    ),
    ("ai_act_disclosure", "es"): (
        "Esta respuesta es generada por un asistente de IA (StackOwl). "
        "La IA puede cometer errores. Verifique la información importante de forma independiente."
    ),
    # Setup flow strings
    ("setup_ready", "en"): "✓ StackOwl is ready — run stackowl serve to start",
    ("setup_ready", "de"): "✓ StackOwl ist bereit — führen Sie stackowl serve aus",
    ("setup_ready", "fr"): "✓ StackOwl est prêt — exécutez stackowl serve pour démarrer",
    ("setup_demo_intro", "en"): (
        "StackOwl Demo Mode\n"
        "==================\n"
        "No API key required. Using MockProvider for all responses.\n"
        "Run: stackowl serve --provider mock"
    ),
}


def localize(key: str, lang: str = "en") -> str:
    """Return the localised string for *key* in *lang*, falling back to English then the key itself."""
    result = _STRINGS.get((key, lang))
    if result is not None:
        return result
    en_result = _STRINGS.get((key, "en"))
    if en_result is not None:
        return en_result
    return key
